     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/Harvester.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

interface IMetaVault {
    function totalAssets() external view returns (uint256);
    function strategies(uint256 index) external view returns (address);
    function allocations(uint256 index) external view returns (uint256);
    function rebalance(uint256[] calldata newAllocations) external;
}

/// @title Harvester
/// @notice Periodic yield collection and rebalance trigger for Omni-Vault.
///         Anyone can call `harvest()` after the cooldown; only the owner
///         can push a new allocation set via `rebalance()`.
contract Harvester is Ownable {
    /// @notice MetaVault this harvester operates against.
    address public vault;

    /// @notice Last successful harvest timestamp.
    uint256 public lastHarvestTime;

    /// @notice Minimum interval between permissionless harvests.
    uint256 public harvestInterval = 24 hours;

    event HarvestExecuted(uint256 totalAssets, uint256 timestamp);
    event Rebalanced(uint256[] allocations);
    event HarvestIntervalUpdated(uint256 interval);

    /// @param _vault MetaVault address.
    constructor(address _vault) Ownable(msg.sender) {
        require(_vault != address(0), "Harvester: zero vault");
        vault = _vault;
    }

    /// @notice Trigger a harvest cycle. Permissionless after `harvestInterval`.
    function harvest() external {
        require(
            block.timestamp >= lastHarvestTime + harvestInterval || msg.sender == owner(),
            "Harvester: cooldown"
        );
        uint256 total = IMetaVault(vault).totalAssets();
        lastHarvestTime = block.timestamp;
        emit HarvestExecuted(total, block.timestamp);
    }

    /// @notice Push a new allocation set (in basis points, summing to 10000) to the vault.
    /// @param newAllocations Per-strategy allocation in bps.
    function rebalance(uint256[] calldata newAllocations) external onlyOwner {
        uint256 sum;
        for (uint256 i = 0; i < newAllocations.length; i++) {
            sum += newAllocations[i];
        }
        require(sum == 10000, "Harvester: bad allocations");
        IMetaVault(vault).rebalance(newAllocations);
        emit Rebalanced(newAllocations);
    }

    /// @notice Update the minimum interval between permissionless harvests.
    /// @param interval New interval in seconds.
    function setHarvestInterval(uint256 interval) external onlyOwner {
        harvestInterval = interval;
        emit HarvestIntervalUpdated(interval);
    }
}

