// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";
import "./StrategyBase.sol";

/// @title NoxStrategy
/// @notice Confidential strategy executed inside iExec NOX TEE workers.
///         Funds remain held by this contract while the actual yield-generation
///         strategy is decided/executed off-chain. An authorized oracle (the TEE)
///         posts signed yield reports back on-chain.
contract NoxStrategy is StrategyBase {
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    /// @notice Address allowed to submit signed yield reports (the iExec TEE result poster).
    address public authorizedOracle;

    /// @notice Latest reported off-chain yield (in underlying asset units).
    uint256 public reportedYield;

    /// @notice Timestamp of the most recent accepted yield report.
    uint256 public lastReportTimestamp;

    /// @notice Underlying asset currently held/staked through NOX.
    uint256 public stakedAmount;

    event YieldReported(uint256 yieldAmount, uint256 timestamp);
    event AuthorizedOracleUpdated(address oracle);

    /// @param _asset Underlying asset (USDC).
    /// @param _vault MetaVault address.
    constructor(address _asset, address _vault) StrategyBase(_asset, _vault) {}

    /// @inheritdoc StrategyBase
    function _depositToProtocol(uint256 amount) internal override {
        stakedAmount += amount;
    }

    /// @inheritdoc StrategyBase
    function _withdrawFromProtocol(uint256 amount) internal override returns (uint256) {
        require(amount <= stakedAmount, "NoxStrategy: exceeds staked");
        stakedAmount -= amount;
        return amount;
    }

    /// @notice Submit a signed yield report from the iExec TEE worker.
    /// @param yieldAmount Cumulative yield to record (in underlying units).
    /// @param signature  ECDSA signature over keccak256(abi.encodePacked(yieldAmount, chainid, this)).
    function submitYieldReport(uint256 yieldAmount, bytes calldata signature) external {
        require(authorizedOracle != address(0), "NoxStrategy: oracle unset");
        bytes32 digest = keccak256(abi.encodePacked(yieldAmount, block.chainid, address(this)))
            .toEthSignedMessageHash();
        address signer = digest.recover(signature);
        require(signer == authorizedOracle, "NoxStrategy: bad signature");

        reportedYield = yieldAmount;
        lastReportTimestamp = block.timestamp;
        emit YieldReported(yieldAmount, block.timestamp);
    }

    /// @notice Total assets = principal staked + last reported off-chain yield.
    function totalAssets() external view override returns (uint256) {
        return stakedAmount + reportedYield;
    }

    /// @notice Update the authorized TEE oracle that may submit yield reports.
    /// @param oracle New oracle address.
    function setAuthorizedOracle(address oracle) external onlyOwner {
        authorizedOracle = oracle;
        emit AuthorizedOracleUpdated(oracle);
    }
}

contracts/strategies/StrategyBase.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/// @title StrategyBase
/// @notice Abstract base contract that all Omni-Vault strategies inherit from.
///         Handles vault authorization, pause control, and the deposit/withdraw
///         entrypoints. Concrete strategies implement protocol-specific logic.
abstract contract StrategyBase is Ownable {
    /// @notice The MetaVault that owns and routes funds through this strategy.
    address public vault;

    /// @notice The underlying asset (e.g. USDC) managed by this strategy.
    IERC20 public asset;

    /// @notice When true, deposits are blocked. Withdrawals remain enabled.
    bool public paused;

    event Paused();
    event Unpaused();
    event StrategyDeposit(uint256 amount);
    event StrategyWithdraw(uint256 amount);

    modifier onlyVault() {
        require(msg.sender == vault, "StrategyBase: not vault");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "StrategyBase: paused");
        _;
    }

    /// @param _asset Underlying ERC20 asset address (e.g. USDC).
    /// @param _vault MetaVault address authorized to call deposit/withdraw.
    constructor(address _asset, address _vault) Ownable(msg.sender) {
        require(_asset != address(0) && _vault != address(0), "StrategyBase: zero addr");
        asset = IERC20(_asset);
        vault = _vault;
    }

    /// @notice Internal hook implemented by subclasses to push funds into the protocol.
    function _depositToProtocol(uint256 amount) internal virtual;

    /// @notice Internal hook implemented by subclasses to pull funds from the protocol.
    /// @return actual amount of asset received back into the strategy.
    function _withdrawFromProtocol(uint256 amount) internal virtual returns (uint256);

    /// @notice Pulls `amount` of asset from the vault and deposits to the underlying protocol.
    /// @param amount Amount of underlying asset to deposit.
    function deposit(uint256 amount) external onlyVault whenNotPaused {
        require(amount > 0, "StrategyBase: zero amount");
        asset.transferFrom(vault, address(this), amount);
        _depositToProtocol(amount);
        emit StrategyDeposit(amount);
    }

    /// @notice Withdraws `amount` of asset from the protocol and returns it to the vault.
    /// @param amount Requested amount to withdraw.
    /// @return received Actual amount transferred back to the vault.
    function withdraw(uint256 amount) external onlyVault returns (uint256 received) {
        require(amount > 0, "StrategyBase: zero amount");
        received = _withdrawFromProtocol(amount);
        asset.transfer(vault, received);
        emit StrategyWithdraw(received);
    }

    /// @notice Pause new deposits. Existing positions remain withdrawable.
    function pause() external onlyOwner {
        paused = true;
        emit Paused();
    }

    /// @notice Resume deposits.
    function unpause() external onlyOwner {
        paused = false;
        emit Unpaused();
    }

    /// @notice Returns the total value of assets managed by this strategy in underlying units.
    function totalAssets() external view virtual returns (uint256);
}

